#include<cstdio>
#include<cstring>
#include<vector>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e4+10,M=3e6+10,INF=0x3f3f3f3f;
int head[N],des[M],nxt[M],cgt=1,s,t,n,m,h2[N],que[N],H,T,dep[N],cap[M],dfn[N],low[N],scc[N],top,stk[N],cdt,tot;bool iss[N];
inline void tarjan(const int &u)
{
	low[u]=dfn[u]=++cdt;iss[stk[++top]=u]=true;grep(u,i)if(cap[i])
	{
		int v=des[i];if(!dfn[v]){tarjan(v);chkmin(low[u],low[v]);}
		else if(iss[v])chkmin(low[u],low[v]);
	}
	if(low[u]==dfn[u]){int v;++tot;do iss[v=stk[top--]]=false,scc[v]=tot;while(u!=v);}
}
inline void ins(const int &x,const int &y,const int &z)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;cap[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;cap[cgt]=0;
}
inline bool bfs()
{
	memset(dep,0,(t+1)<<2);dep[que[H=T=0]=s]=1;
	while(H<=T){int u=que[H++];grep(u,i)if(cap[i]&&!dep[des[i]])dep[que[++T]=des[i]]=dep[u]+1;} return dep[t];
}
inline int dfs(const int &u=s,int in=INF)
{
	if(u==t)return in;int out=0;
	for(int &i=h2[u];i;i=nxt[i])if(cap[i]&&dep[des[i]]==dep[u]+1)
	{
		int tmp=dfs(des[i],min(in,cap[i]));
		cap[i]-=tmp;cap[i^1]+=tmp;out+=tmp;if(!(in-=tmp))break;
	}
	return out?out:dep[u]=0;
}
inline int dinic(){int ans=0;while(bfs())memcpy(h2,head,(t+1)<<2),ans+=dfs();return ans;}
bool vis[N],col[N],isc[M];std::vector<int> G[N];std::vector<std::pair<int,int>> ans,Ans;
inline void Col(const int &u,const int &c=0){vis[u]=true;col[u]=c;for(int v:G[u])if(!vis[v])Col(v,c^1);}
int main()
{
//	freopen("city.in","r",stdin);
//	freopen("city.out","w",stdout);
	n=read();m=read();rep(1,m,i){int x=read(),y=read();G[x].push_back(y);G[y].push_back(x);}rep(1,n,i)if(!vis[i])Col(i);
	s=0;t=n+1;rep(1,n,i)if(col[i])ins(i,t,1);else ins(s,i,1);rep(1,n,u)if(!col[u])for(int v:G[u])ins(u,v,1);dinic();
	for(int i=2;i<=cgt;i+=2)if(des[i^1]!=s&&des[i]!=t&&!cap[i]){int u=des[i],v=des[i^1];if(u>v){int tmp(u);u=v;v=tmp;}ans.push_back(std::make_pair(u,v));}
	rep(1,n,i)if(!dfn[i])tarjan(i);std::sort(ans.begin(),ans.end());for(std:: pair<int,int> v: ans)if(scc[v.first]!=scc[v.second])Ans.push_back(v);
	printf("%d\n",int(Ans.size()));for(std::pair<int,int> v: Ans)printf("%d %d\n",v.first,v.second);
}
